pub(super) fn palette(name: &str, appearance: Appearance) -> Option<Palette> {
    BUILTIN_THEMES
        .iter()
        .find(|theme| theme.name == name)
        .map(|theme| {
            let colors = match appearance {
                Appearance::Dark => theme.dark,
                Appearance::Light => theme.light,
            };
            expand(colors)
        })
}

#[cfg(test)]
pub(super) fn names() -> impl Iterator<Item = &'static str> {
    BUILTIN_THEMES.iter().map(|theme| theme.name)
}

fn expand(colors: [u32; COLOR_COUNT]) -> Palette {
    let colors = colors.map(decode);
    let ink = colors[5];
    let muted = colors[6];
    Palette {
        canvas: colors[0],
        panel: colors[1],
        surface_alt: colors[2],
        raised: colors[3],
        selected: colors[4],
        inactive_selected: colors[3],
        ink,
        soft: super::soft_text(ink, muted),
        muted,
        faint: colors[7],
        accent: colors[8],
        purple: colors[9],
        green: colors[10],
        yellow: colors[11],
        red: colors[12],
        cyan: colors[13],
        orange: colors[14],
        add_bg: colors[15],
        remove_bg: colors[16],
        graph_colors: [
            colors[8], colors[9], colors[10], colors[11], colors[12], colors[13], colors[14],
            colors[17],
        ],
    }
}

fn decode(value: u32) -> Color {
    match value & 0xff00_0000 {
        RESET => Color::Reset,
        INDEXED => Color::Indexed(value as u8),
        _ => Color::Rgb((value >> 16) as u8, (value >> 8) as u8, value as u8),
    }
}
